    doubled = s + s  # Concatenate s with itself
    return goal in doubled

code.C:
bool canRotate(char s[], char goal[]) {
    int lenS = strlen(s);
    int lenG = strlen(goal);

    if (lenS != lenG) return false;

    char doubled[201]; // Max length 100 + 100 + 1 for null terminator
    strcpy(doubled, s);
    strcat(doubled, s); // Concatenate s with itself

    // Check if goal is a substring of doubled
    if (strstr(doubled, goal) != NULL) {
        return true;
    }
    return false;
}

